      code: "from collections import deque\n\n# Recursive DFS: swap the order of the three lines for pre/in/post\ndef inorder(root):\n    res = []\n    def dfs(node):\n        if not node:\n            return\n        dfs(node.left)\n        res.append(node.val)   # move this line up for preorder, down for postorder\n        dfs(node.right)\n    dfs(root)\n    return res\n\n# Iterative inorder with an explicit stack\ndef inorder_iter(root):\n    res, stack, cur = [], [], root\n    while cur or stack:\n        while cur:\n            stack.append(cur)\n            cur = cur.left\n        cur = stack.pop()\n        res.append(cur.val)\n        cur = cur.right\n    return res\n\n# Level order (BFS)\ndef level_order(root):\n    if not root:\n        return []\n    res, q = [], deque([root])\n    while q:\n        level = []\n        for _ in range(len(q)):      # snapshot the level size\n            node = q.popleft()\n            level.append(node.val)\n            if node.left:\n                q.append(node.left)\n            if node.right:\n                q.append(node.right)\n        res.append(level)\n    return res",
