      language: "python",
      code: "class TrieNode:\n    def __init__(self):\n        self.children = {}      # char -> TrieNode\n        self.is_word = False\n\nclass Trie:\n    def __init__(self):\n        self.root = TrieNode()\n\n    def insert(self, word):\n        node = self.root\n        for c in word:\n            if c not in node.children:\n                node.children[c] = TrieNode()\n            node = node.children[c]\n        node.is_word = True         # mark end of a complete word\n\n    def search(self, word):\n        node = self._walk(word)\n        return node is not None and node.is_word\n\n    def startsWith(self, prefix):\n        return self._walk(prefix) is not None\n\n    def _walk(self, s):\n        node = self.root\n        for c in s:\n            if c not in node.children:\n                return None\n            node = node.children[c]\n        return node\n\n    # Wildcard search where '.' matches any single character\n    def search_wildcard(self, word):\n        def dfs(i, node):\n            if i == len(word):\n                return node.is_word\n            c = word[i]\n            if c == '.':\n                return any(dfs(i + 1, child) for child in node.children.values())\n            return c in node.children and dfs(i + 1, node.children[c])\n        return dfs(0, self.root)",
